class Solution:
    def checkSubarraySum(self, nums: List[int], k: int) -> bool:
        n = len(nums)
        prefix_sum = {0: -1}
        curr_sum = 0
        for i in range(n):
            curr_sum += nums[i]
            if k != 0:
                curr_sum %= k
            if curr_sum in prefix_sum:
                if i - prefix_sum[curr_sum] > 1:
                    return True
            else:
                prefix_sum[curr_sum] = i
        return False
